20	  cb_assert(coinbase::bytes_to_bits(s.size) >= SEC_P_COM && "DRBG requires SEC_P_COM bits of entropy");
21	  if (s.size == 32) {
22	    ctr.init(s.take(16), s.data + 16);
23	  } else {
24	    init();
