56	bn256_t drbg_aes_ctr_t::gen_bn256(const mod_t& mod) {
57	  bn256_t r;
58	
59	  const bn_t& m = mod;
60	  const BIGNUM* mbn = m;
61	  if (mbn->top == 4 && mbn->d[3] == 0xffffffffffffffff && mbn->d[2] >= 0xffffffffffff0000) {
62	    // Fast path for near-2^256 moduli. This intentionally skips reduction for
63	    // speed; callers of gen_bn256 must tolerate the negligible chance that the
64	    // result is >= mod.
65	    byte_t rnd[32];
66	    gen(byte_ptr(rnd), sizeof(rnd));
67	    r = bn256_t::from_bin(mem_t(rnd, sizeof(rnd)));
68	    return r;
69	  }
70	
71	  byte_t rnd[40];
72	  gen(byte_ptr(rnd), sizeof(rnd));
73	
74	  uint64_t temp[8] = {0};
75	  temp[0] = coinbase::be_get_8(rnd + 32);
76	  temp[1] = coinbase::be_get_8(rnd + 24);
77	  temp[2] = coinbase::be_get_8(rnd + 16);
78	  temp[3] = coinbase::be_get_8(rnd + 8);
79	  temp[4] = coinbase::be_get_8(rnd + 0);
80	  r = bn256_t::reduce(temp, mod);
81	  return r;
82	}
