8	 * @specs:
9	 * - basic-primitives-spec | drbg-sample-string-1P
10	 */
11	buf_t drbg_sample_string(mem_t seed, int bits) {
12	  cb_assert(bits > 0);
13	  crypto::drbg_aes_ctr_t drbg(seed);
14	  return drbg.gen(coinbase::bits_to_bytes(bits));
15	}
