17	/**
18	 * @specs:
19	 * - basic-primitives-spec | drbg-sample-number-1P
20	 */
21	bn_t drbg_sample_number(mem_t seed, const mod_t& p)  // modulo p
22	{
23	  buf_t r = drbg_sample_string(seed, p.get_bits_count() + SEC_P_STAT);
24	  return bn_t::from_bin(r) % p;
25	}
