27	int drbg_sample_number(mem_t seed, int m)  // modulo m
28	{
29	  cb_assert(m > 0);
30	  // Used only for deterministic non-cryptographic choices. The `% m` mapping
31	  // is biased, so cryptographic challenge/scalar sampling should use mod_t.
32	  buf_t r = drbg_sample_string(seed, 64);
33	  return coinbase::be_get_8(r.data()) % m;
34	}
