46	/**
47	 * In the basic-primitives-spec.pdf, section 4.2, we describe how we create a "Random Oracle"
48	 * using an HMAC with a hardwired key.
49	 * It is important that this is NOT used as the seed.
50	 * Rather seeds are random values and are passed as input to an hmac keyed by this hardwired value.
51	 */
52	// The following is the first 16 bytes of the result of SHA256("Coinbase Random Oracle Key")
53	static const byte_t global_key[16] = {0xe5, 0xef, 0x49, 0x37, 0x19, 0x89, 0x88, 0x83,
54	                                      0x50, 0xc4, 0x56, 0x5c, 0xca, 0x19, 0x08, 0x4a};
55	
