71	  cb_assert(bits > 0);
72	  buf_t h = final();
73	  int bytes = coinbase::bits_to_bytes(bits);
74	
75	  if (bytes <= 32) {
76	    buf_t out = h.take(bytes);
77	    return out;
78	  }
79	
80	  return drbg_sample_string(h, bits);
81	}
