93	std::vector<bn_t> hash_numbers_t::mod(const mod_t& p) {
94	  cb_assert(l > 0 && "hash_numbers_t::mod(): call count(l) with l > 0 before mod()");
95	  buf_t h = final();
96	
97	  int bits_per_value = p.get_bits_count() + SEC_P_STAT;
98	  int bytes_per_value = bits_to_bytes(bits_per_value);
99	  buf_t t = drbg_sample_string(h, bytes_to_bits(bytes_per_value) * l);
100	
101	  std::vector<bn_t> r(l);
102	  for (int i = 0; i < l; i++) {
103	    mem_t bin = t.range(i * bytes_per_value, bytes_per_value);
104	    r[i] = bn_t::from_bin(bin) % p;
105	  }
106	
107	  return r;
108	}
109	
110	std::vector<bn256_t> hash_numbers_t::mod256(const mod_t& p) {
111	  cb_assert(l > 0 && "hash_numbers_t::mod(): call count(l) with l > 0 before mod()");
112	  const int mod_bits = p.get_bits_count();
113	  cb_assert(mod_bits <= 256 && "hash_numbers_t::mod256(): only supports moduli up to 256 bits");
114	  buf_t h = final();
115	
116	  int bits_per_value = mod_bits + SEC_P_COM;
117	  int bytes_per_value = bits_to_bytes(bits_per_value);
118	  buf_t t = drbg_sample_string(h, bytes_per_value * 8 * l);
119	
120	  std::vector<bn256_t> r(l);
121	  uint64_t temp[8] = {0};
122	  size_t copy_size = 0;
123	  if (bytes_per_value < 0) {
124	    cb_assert(false && "hash_numbers_t::mod256(): negative sample size");
125	  } else {
126	    copy_size = static_cast<size_t>(bytes_per_value);
127	  }
128	  if (copy_size > sizeof(temp)) {
129	    cb_assert(false && "hash_numbers_t::mod256(): sampled value exceeds reducer input size");
130	    copy_size = sizeof(temp);
131	  }
132	
133	  for (int i = 0; i < l; i++) {
134	    mem_t bin = t.range(i * bytes_per_value, bytes_per_value);
135	    bin.reverse();
136	    memcpy(temp, bin.data, copy_size);
137	
138	    MODULO(p) r[i] = bn256_t::reduce(temp);
139	  }
140	  coinbase::secure_bzero(byte_ptr(temp), sizeof(temp));
141	
142	  return r;
143	}
