145	ecc_point_t hash_curve_t::curve(ecurve_t curve) {
146	  dylog_disable_scope_t dylog_disable_scope;
147	
148	  ecc_point_t Q(curve);
149	  for (int i = 0; true; i++) {
150	    ro::hash_string_t alt;
151	    hmac.copy_state(alt.hmac);
152	    alt.encode_and_update(i);
153	
154	    buf_t bin = alt.bitlen(curve.bits());
155	    if (curve.hash_to_point(bin, Q)) break;
156	  }
157	
158	  return Q;
159	}
