9	std::vector<bn_t> share_and(const mod_t& q, const bn_t& x, const int n, crypto::drbg_aes_ctr_t* drbg) {
10	  cb_assert(n > 0);
11	  std::vector<bn_t> shares(n);
12	  bn_t sum = 0;
13	  for (int i = 1; i < n; i++) {
14	    if (drbg)
15	      shares[i] = drbg->gen_bn(q);
16	    else
17	      shares[i] = bn_t::rand(q);
18	    MODULO(q) sum += shares[i];
19	  }
20	  MODULO(q) shares[0] = x - sum;
21	  return shares;
22	}
