24	std::pair<std::vector<bn_t>, std::vector<bn_t>> share_threshold(const mod_t& q, const bn_t& a, const int threshold,
25	                                                                const int n, const std::vector<bn_t>& pids,
26	                                                                crypto::drbg_aes_ctr_t* drbg) {
27	  cb_assert(threshold > 0);
28	  cb_assert(n >= threshold);
29	  cb_assert(n <= pids.size());
30	  std::vector<bn_t> shares(n);
31	  std::vector<bn_t> b(threshold);
32	  shares.resize(n);
33	  b.resize(threshold);
34	  b[0] = a;
35	  for (int i = 1; i < threshold; i++) {
36	    if (drbg)
37	      b[i] = drbg->gen_bn(q);
38	    else
39	      b[i] = bn_t::rand(q);
40	  }
41	  for (int i = 0; i < n; i++) {
42	    cb_assert(pids[i] != 0);
43	    shares[i] = horner_poly(q, b, pids[i]);
44	  }
45	  return {shares, b};
46	}
