57	error_t node_t::validate_tree(std::set<pname_t>& names) const {
58	  error_t rv = UNINITIALIZED_ERROR;
59	  if (name.empty() && parent) return coinbase::error(E_BADARG, "unnamed node");
60	  if (!parent && !name.empty()) return coinbase::error(E_BADARG, "named root node");
61	  int n = int(children.size());
62	
63	  if (names.count(name) > 0) return coinbase::error(E_BADARG, "name duplication");
64	  names.insert(name);
65	
66	  switch (type) {
67	    case node_e::LEAF:
68	      if (threshold != 0) return coinbase::error(E_BADARG, "no threshold node");
69	      if (n != 0) return coinbase::error(E_BADARG, "leaf node must not have children");
70	      return SUCCESS;
71	    case node_e::AND:
72	      if (threshold != 0) return coinbase::error(E_BADARG, "no threshold node");
73	      if (n == 0) return coinbase::error(E_BADARG, "AND node must have children");
74	      break;
75	    case node_e::OR:
76	      if (threshold != 0) return coinbase::error(E_BADARG, "no threshold node");
77	      if (n == 0) return coinbase::error(E_BADARG, "OR node must have children");
78	      break;
79	    case node_e::THRESHOLD:
80	      if (threshold < 1) return coinbase::error(E_BADARG, "invalid threshold");
81	      if (threshold > n) return coinbase::error(E_BADARG, "invalid threshold");
82	      break;
83	    default:
84	      return coinbase::error(E_BADARG, "invalid node type");
85	  }
86	
87	  for (const node_t* child : children)
88	    if (rv = child->validate_tree(names)) return rv;
89	
90	  return SUCCESS;
91	}
