240	bool node_t::enough_for_quorum(const std::set<pname_t>& names) const {
241	  int count = 0;
242	
243	  switch (type) {
244	    case node_e::LEAF:
245	      return names.find(this->name) != names.end();
246	    case node_e::OR:
247	      for (int i = 0; i < get_n(); i++) {
248	        if (children[i]->enough_for_quorum(names)) return true;
249	      }
250	      return false;
251	    case node_e::AND:
252	      for (int i = 0; i < get_n(); i++) {
253	        if (!children[i]->enough_for_quorum(names)) return false;
254	      }
255	      return true;
256	    case node_e::THRESHOLD:
257	      for (int i = 0; i < get_n(); i++) {
258	        if (!children[i]->enough_for_quorum(names)) continue;
259	        count++;
260	        if (count >= threshold) return true;
261	      }
262	      return false;
263	    case node_e::NONE: {
264	      return false;
265	    } break;
266	  }
267	
268	  cb_assert(false);
269	  return false;
270	}
