272	static void share_recursive(const mod_t& q, const ecc_point_t& G, const node_t* node, const bn_t& a,
273	                            const bool output_additional_data, ac_shares_t& ac_shares,
274	                            ac_internal_shares_t& ac_internal_shares, ac_internal_pub_shares_t& ac_internal_pub_shares,
275	                            drbg_aes_ctr_t* drbg) {
276	  auto sorted_children = node->get_sorted_children();
277	  int n = int(sorted_children.size());
278	
279	  std::vector<bn_t> children_a(n);
280	  std::vector<bn_t> b;
281	
282	  if (output_additional_data) {
283	    ac_internal_shares[node->name] = a;
284	    ac_internal_pub_shares[node->name] = a * G;
285	  }
286	
287	  switch (node->type) {
288	    case node_e::LEAF:
289	      ac_shares[node->name] = a;
290	
291	      break;
292	    case node_e::OR:
293	      for (int i = 0; i < n; i++)
294	        share_recursive(q, G, sorted_children[i], a, output_additional_data, ac_shares, ac_internal_shares,
295	                        ac_internal_pub_shares, drbg);
296	
297	      break;
298	    case node_e::AND:
299	      children_a = share_and(q, a, n, drbg);
300	      for (int i = 0; i < n; i++)
301	        share_recursive(q, G, sorted_children[i], children_a[i], output_additional_data, ac_shares, ac_internal_shares,
302	                        ac_internal_pub_shares, drbg);
303	
304	      break;
305	    case node_e::THRESHOLD: {
306	      std::vector<bn_t> pids(n);
307	      for (int i = 0; i < n; i++) pids[i] = sorted_children[i]->get_pid();
308	      b.resize(node->threshold);
309	      std::tie(children_a, b) = share_threshold(q, a, node->threshold, n, pids, drbg);
310	      for (int i = 0; i < n; i++)
311	        share_recursive(q, G, sorted_children[i], children_a[i], output_additional_data, ac_shares, ac_internal_shares,
312	                        ac_internal_pub_shares, drbg);
313	
314	    } break;
315	    case node_e::NONE: {
316	      return;
317	    } break;
318	  }
319	}
