321	ac_shares_t ac_t::share(const mod_t& q, const bn_t& x, drbg_aes_ctr_t* drbg) const {
322	  ac_shares_t shares;
323	  ac_internal_shares_t dummy;
324	  ac_internal_pub_shares_t dummy_pub;
325	
326	  bool output_additional_data = false;
327	  ecc_point_t dummy_G;
328	  share_recursive(q, dummy_G, root, x, output_additional_data, shares, dummy, dummy_pub, drbg);
329	  return shares;
330	}
