7	/**
8	 * @notes:
9	 * - This is a more complicated version of the `lagrange_basis` defined below, since it is constant-time.
10	 */
11	void lagrange_basis(const bn_t& x, const std::vector<int>& pids, int current, const mod_t& q, bn_t& numerator,
12	                    bn_t& denominator) {
13	  int m = (int)pids.size();
14	  numerator = q.to_mont(1);
15	  denominator = 1;
16	  bn_wexpand(denominator, m / 2);
17	
18	  bool neg = false;
19	  const bn_t& mod = q.value();
20	
21	  bn_t num_delta = x;
22	  bn_t num_delta_mont;
23	  int old = 0;
24	  auto bn_ctx = bn_t::thread_local_storage_bn_ctx();
25	  auto mont_ctx = q.get_mont_ctx();
26	
27	  for (int j = 0; j < m; j++) {
28	    if (current == pids[j]) continue;
29	    cb_assert(pids[j] > 0 && "pids must be positive");
30	
31	    int denom_delta = current - pids[j];
32	    if (denom_delta < 0) {
33	      denom_delta = -denom_delta;
34	      neg = !neg;
35	    }
36	
37	    BN_mul_word(denominator, denom_delta);  // denominator *= delta;
38	
39	    BN_sub_word(num_delta, pids[j]);
40	    BN_add_word(num_delta, old);
41	    old = pids[j];
42	
43	    BN_to_montgomery(num_delta_mont, num_delta, mont_ctx, bn_ctx);
44	    BN_mod_mul_montgomery(numerator, numerator, num_delta_mont, mont_ctx, bn_ctx);
45	  }
46	
47	  BN_div(nullptr, denominator, denominator, mod, bn_ctx);
48	  if (neg) BN_sub(denominator, mod, denominator);
49	
50	  BN_from_montgomery(numerator, numerator, mont_ctx, bn_ctx);
51	}
52	
53	bn_t lagrange_basis(const bn_t& x, const std::vector<int>& pids, int current, const mod_t& q) {
54	  bn_t numerator, denominator;
55	  lagrange_basis(x, pids, current, q, numerator, denominator);
56	
57	  auto bn_ctx = bn_t::thread_local_storage_bn_ctx();
58	  const bn_t& mod = q.value();
59	  BN_mod_inverse(denominator, denominator, mod,
60	                 bn_ctx);  // denominator = 1/denominator mod q;
61	
62	  BN_mod_mul(numerator, numerator, denominator, mod,
63	             bn_ctx);  // numerator = numerator * denominator
64	  return numerator;
65	}
66	
67	bn_t lagrange_basis(const bn_t& x, const std::vector<bn_t>& pids, const bn_t& current_pid, const mod_t& q) {
68	  vartime_scope_t vartime_scope;
69	
70	  int m = (int)pids.size();
71	  bn_t numerator = 1;
72	  bn_t denominator = 1;
73	
74	  for (int j = 0; j < m; j++) {
75	    const bn_t& pid = pids[j];
76	    cb_assert(pid > 0);
77	
78	    if (current_pid == pid) continue;
79	    MODULO(q) numerator *= x - pid;
80	    MODULO(q) denominator *= current_pid - pid;
81	  }
82	
83	  bn_t result;
84	  MODULO(q) result = numerator / denominator;
85	  return result;
86	}
