88	bn_t lagrange_partial_interpolate(const bn_t& x, const std::vector<bn_t>& shares,
89	                                  const std::vector<bn_t>& pids_for_shares, const std::vector<bn_t>& all_pids,
90	                                  const mod_t& q) {
91	  cb_assert(pids_for_shares.size() == shares.size() && "shares and pids_for_shares must have the same size");
92	  cb_assert(all_pids.size() >= shares.size() && "all_pids must have at least as many elements as shares");
93	  int m = (int)shares.size();
94	  bn_t secret = 0;
95	
96	  for (int i = 0; i < m; i++) {
97	    bn_t lambda = lagrange_basis(x, all_pids, pids_for_shares[i], q);
98	    MODULO(q) secret += lambda * shares[i];
99	  }
100	
101	  return secret;
102	}
103	
104	bn_t lagrange_interpolate(const bn_t& x, const std::vector<bn_t>& shares, const std::vector<bn_t>& pids,
105	                          const mod_t& q) {
106	  cb_assert(shares.size() == pids.size() && "shares and pids must have the same size");
107	  return lagrange_partial_interpolate(x, shares, pids, pids, q);
108	}
