110	/* Lagrange in exponent */
111	
112	ecc_point_t lagrange_partial_interpolate_exponent(const bn_t& x, const std::vector<ecc_point_t>& shares,
113	                                                  const std::vector<bn_t>& pids_for_shares,
114	                                                  const std::vector<bn_t>& all_pids) {
115	  cb_assert(shares.size() == pids_for_shares.size() && "shares and pids_for_shares must have the same size");
116	  cb_assert(all_pids.size() >= shares.size() && "all_pids must have at least as many elements as shares");
117	  int m = (int)shares.size();
118	  cb_assert(m > 0 && "shares must have at least one element");
119	  ecurve_t curve = shares[0].get_curve();
120	  const mod_t& q = curve.order();
121	  ecc_point_t R = curve.infinity();
122	
123	  for (int i = 0; i < m; i++) {
124	    bn_t lambda = lagrange_basis(x, all_pids, pids_for_shares[i], q);
125	    R += lambda * shares[i];
126	  }
127	
128	  return R;
129	}
