131	ecc_point_t lagrange_interpolate_exponent(const bn_t& x, const std::vector<ecc_point_t>& shares,
132	                                          const std::vector<bn_t>& pids) {
133	  cb_assert(shares.size() == pids.size() && "shares and pids must have the same size");
134	  return lagrange_partial_interpolate_exponent(x, shares, pids, pids);
135	}
