137	bn_t horner_poly(const mod_t& q, const std::vector<bn_t>& a, const bn_t& x) {
138	  int count = int(a.size());
139	  bn_t b = a[count - 1];
140	  for (int i = count - 2; i >= 0; i--) {
141	    MODULO(q) b = a[i] + b * x;
142	  }
143	  return b;
144	}
145	
146	ecc_point_t horner_poly(const std::vector<ecc_point_t>& A, const bn_t& x) {
147	  int count = int(A.size());
148	  ecc_point_t B = A[count - 1];
149	  for (int i = count - 2; i >= 0; i--) {
150	    B = A[i] + x * B;
151	  }
152	  return B;
153	}
