15	void paillier_t::convert(coinbase::converter_t& converter) {
16	  converter.convert(has_private);
17	  converter.convert(N);
18	  if (has_private) {
19	    converter.convert(p);
20	    converter.convert(q);
21	  }
22	
23	  if (!converter.is_write()) {
24	    if (converter.is_error()) return;
25	    if (N.get_bits_count() > bit_size) {
26	      converter.set_error();
27	      return;
28	    }
29	    if (has_private) {
30	      // This path rebuilds a private key from serialized state without semantically validating `p`/`q`.
31	      // It is intended for trusted local blobs.
32	      update_private();
33	    } else {
34	      // This path only rebuilds cached public state from the deserialized modulus.
35	      // `mod_t::convert()` already enforces the basic modulus representation, but callers are still responsible
36	      // for any higher-level/context-specific validation at the boundary after deserialization.
37	      update_public();
38	    }
39	  }
40	}
