42	void paillier_t::generate() {
43	  // NOTE: This generates Paillier without safe primes since safe primes are only needed for threshold Paillier
44	  rsa_prv_key_t key;
45	  key.generate(bit_size);
46	  p = key.get_p();
47	  q = key.get_q();
48	
49	  N = mod_t(p * q, /* multiplicative_dense */ true);
50	
51	  update_private();
52	  has_private = true;
53	}
54	
55	void paillier_t::update_public() {
56	  // Internal helper: callers must ensure `N` has already been validated / constructed as a valid `mod_t`.
57	  // The untrusted-input boundary is handled by `create_pub()` or by `mod_t::convert()` during deserialization.
58	  // calculate N^2
59	  NN = mod_t(N * N, /* multiplicative_dense */ true);
60	}
61	
62	void paillier_t::update_private() {
63	  update_public();
64	
65	  if (p < q) std::swap(p, q);
66	
67	  // calculating phi(N) = (p-1)(q-1)
68	  // Side-channel note:
69	  // This uses generic bignum multiplication on secret primes. The dominant timing signal in typical BN code is
70	  // operand length (`top`), which is effectively fixed for RSA-2048 primes generated by our keygen. Also, this
71	  // function is used for key setup (generate/load), not an attacker-triggerable hot path. We understand the
72	  // general risk of variable-time big integer operations on secrets. Given the fixed operand size here and the
73	  // non-interactive/offline usage, we consider it acceptable to use generic bignum multiplication in this setup
74	  // path, even though the operation is not theoretically constant-time.
75	  phi_N = (p - 1) * (q - 1);
76	
77	  inv_phi_N = N.inv(phi_N);
78	
79	  // Precompute N^{-1} mod 2^bit_size for constant-time L(u) extraction during decryption.
80	  // (See `paillier_t::decrypt` for details.)
81	  {
82	    bn_t two_pow = bn_t(1) << bit_size;  // 2^2048
83	    auto* inv = BN_mod_inverse(inv_N_mod_2k, N.value(), two_pow, bn_t::thread_local_storage_bn_ctx());
84	    cb_assert(inv && "paillier_t::update_private: failed to invert N mod 2^bit_size");
85	
86	    constexpr int BN_ULONG_BITS = int(sizeof(BN_ULONG) * 8);
87	    static_assert(bit_size % BN_ULONG_BITS == 0, "Paillier bit_size must be BN_ULONG-word aligned");
88	    constexpr int k_words = bit_size / BN_ULONG_BITS;
89	    BIGNUM& inv_bn = *(BIGNUM*)inv_N_mod_2k;
90	    cb_assert(bn_wexpand(&inv_bn, k_words));
91	    // Zero any unused high words and force a fixed-top representation so decrypt can read `d[0..k_words)`.
92	    for (int i = inv_bn.top; i < k_words; i++) inv_bn.d[i] = 0;
93	    inv_bn.top = k_words;
94	    inv_bn.neg = 0;
95	    inv_bn.flags |= BN_FLG_FIXED_TOP | BN_FLG_CONSTTIME;
96	  }
97	
98	  // p^2
99	  bn_t p_sqr = p * p;
100	
101	  // q^2
102	  bn_t q_sqr = q * q;
103	
104	  // (q^2)^-1 (p^2)
105	  bn_t q_sqr_inverse = mod_t(p_sqr, /* multiplicative_dense */ true).inv(q_sqr);
106	
107	  // p^2 - p
108	  bn_t p_sqr_minus_p = p_sqr - p;
109	
110	  // q^2 - q
111	  bn_t q_sqr_minus_q = q_sqr - q;
112	
113	  bn_t phi_N_mod_p_sqr_minus_p;
114	  bn_t phi_N_mod_q_sqr_minus_q;
115	  bn_t N_mod_p_sqr_minus_p;
116	  bn_t N_mod_q_sqr_minus_q;
117	
118	  MODULO(LARGEST_PRIME_MOD_2048) {
119	    // The below calculations are based on the fact that q < p < 2q
120	    bn_t p_minus_q = p - q;
121	    phi_N_mod_p_sqr_minus_p = phi_N;
122	    phi_N_mod_q_sqr_minus_q = (p_minus_q - 1) * (q - 1);
123	    N_mod_p_sqr_minus_p = N;
124	    N_mod_q_sqr_minus_q = (p_minus_q + 1) * q;
125	  }
126	
127	  crt_dec.p = mod_t(p_sqr, /* multiplicative_dense */ true);
128	  crt_dec.q = mod_t(q_sqr, /* multiplicative_dense */ true);
129	  crt_dec.dp = phi_N_mod_p_sqr_minus_p;
130	  crt_dec.dq = phi_N_mod_q_sqr_minus_q;
131	  crt_dec.qinv = q_sqr_inverse;
132	
133	  crt_enc.p = mod_t(p_sqr, /* multiplicative_dense */ true);
134	  crt_enc.q = mod_t(q_sqr, /* multiplicative_dense */ true);
135	  crt_enc.dp = N_mod_p_sqr_minus_p;
136	  crt_enc.dq = N_mod_q_sqr_minus_q;
137	  crt_enc.qinv = q_sqr_inverse;
138	}
