210	bn_t paillier_t::crt_t::compute_power(const bn_t& c, const mod_t& NN) const {
211	  bn_t c_mod_p = c % p;
212	  bn_t c_mod_q = c % q;
213	
214	  bn_t mp, mq;
215	  MODULO(p) mp = c_mod_p.pow(dp);
216	  MODULO(q) mq = c_mod_q.pow(dq);
217	
218	  bn_t h;
219	  MODULO(p) h = qinv * (mp - mq);
220	  bn_t dec;
221	  MODULO(NN) dec = mq + h * q;
222	  return dec;
223	}
