225	bn_t paillier_t::encrypt(const bn_t& src, const bn_t& rand) const {
226	  cb_assert(src >= 0 && src < N && "paillier_t::encrypt: src must be in [0, N)");
227	  bn_t rn;
228	  if (has_private) {
229	    rn = crt_enc.compute_power(rand, NN);
230	  } else {
231	    cb_assert(mod_t::coprime(rand, N) && "paillier_t::encrypt: rand and N are not coprime");
232	    MODULO(NN) rn = rand.pow(N);
233	  }
234	
235	  MODULO(NN) rn *= src * N + 1;
236	  return rn;
237	}
