239	bn_t paillier_t::decrypt(const bn_t& src) const {
240	  cb_assert(src > 0 && src < NN && "paillier_t::decrypt: src must be in (0, N^2)");
241	  cb_assert(mod_t::coprime(src, N) && "paillier_t::decrypt: src must be coprime with N");
242	  bn_t c1;
243	
244	  if (has_private) {
245	    c1 = crt_dec.compute_power(src, NN);
246	  } else {
247	    cb_assert(false);
248	  }
249	
250	  // Side-channel note:
251	  // This is the Paillier L(u) step: L(c1) = (c1 - 1) / N, with c1 ∈ Z_{N^2}.
252	  // For odd N, division by N can be replaced by multiplication with N^{-1} modulo 2^k:
253	  //   (c1 - 1) = N * L(c1)  ⇒  L(c1) ≡ (c1 - 1) * N^{-1} (mod 2^k)
254	  // With k = 2048 and 0 ≤ L(c1) < N < 2^k, this recovers L(c1) exactly from the low k bits.
255	  constexpr int BN_ULONG_BITS = int(sizeof(BN_ULONG) * 8);
256	  static_assert(bit_size % BN_ULONG_BITS == 0, "Paillier bit_size must be BN_ULONG-word aligned");
257	  constexpr int k_words = bit_size / BN_ULONG_BITS;
258	
259	  const BIGNUM& c1_bn = *(const BIGNUM*)c1;
260	  cb_assert(c1_bn.top >= 0);
261	
262	  // tmp_low = (c1 - 1) mod 2^k (little-endian words)
263	  BN_ULONG tmp_low[k_words];
264	  BN_ULONG borrow = 1;
265	  for (int i = 0; i < k_words; i++) {
266	    BN_ULONG w = 0;
267	    if (i < c1_bn.top) w = c1_bn.d[i];
268	    tmp_low[i] = w - borrow;
269	    borrow = (borrow && (w == 0)) ? 1 : 0;
270	  }
271	
272	  // m1_words = tmp_low * inv_N_mod_2k mod 2^k
273	  const BIGNUM& inv_bn = *(const BIGNUM*)inv_N_mod_2k;
274	  cb_assert(inv_bn.top == k_words);
275	  BN_ULONG prod[k_words * 2];
276	  bn_mul_normal(prod, tmp_low, k_words, inv_bn.d, k_words);
277	
278	  bn_t m1;
279	  BIGNUM& m1_bn = *(BIGNUM*)m1;
280	  cb_assert(bn_wexpand(&m1_bn, k_words));
281	  std::copy(prod, prod + k_words, m1_bn.d);
282	  m1_bn.top = k_words;
283	  m1_bn.neg = 0;
284	  m1_bn.flags |= BN_FLG_FIXED_TOP | BN_FLG_CONSTTIME;
285	
286	  MODULO(N) m1 *= inv_phi_N;
287	  return m1;
288	}
