290	bn_t paillier_t::rerand(const bn_t& cipher) const {
291	  bn_t r = bn_t::rand(N);
292	
293	  bn_t rn;
294	  if (has_private) {
295	    rn = crt_enc.compute_power(r, NN);
296	  } else {
297	    cb_assert(mod_t::coprime(r, N));
298	    MODULO(NN) rn = r.pow(N);
299	  }
300	  MODULO(NN) rn *= cipher;
301	  return rn;
302	}
