304	bn_t paillier_t::get_cipher_randomness(const bn_t& plain, const bn_t& cipher) const {
305	  bn_t c;
306	  bn_t result;
307	  bn_t temp = mod_t::N_inv_mod_phiN_2048(N, phi_N);  // temp = 1 / N mod phi_N
308	
309	  MODULO(NN) { c = cipher / (plain * N + 1); }
310	
311	  MODULO(N) { result = c.pow(temp); }
312	
313	  return result;
314	}
