316	error_t paillier_t::verify_cipher(const mod_t& N, const mod_t& NN, const bn_t& cipher) {
317	  vartime_scope_t vartime_scope;
318	  error_t rv = UNINITIALIZED_ERROR;
319	  if (rv = coinbase::crypto::check_open_range(0, cipher, NN)) return rv;
320	  if (!mod_t::coprime(cipher, N)) return coinbase::error(E_CRYPTO);
321	  return SUCCESS;
322	}
323	// If the private key is present, we return a single uniform sample in Z_N,
324	// which lands in Z_N^* with overwhelming probability; otherwise we either
325	// resample until gcd(r, N) == 1 or return an error.
326	error_t paillier_t::rand_N_star(bn_t& r, bool resample_until_coprime) const {
327	  r = bn_t::rand(N);
328	  if (has_private) return SUCCESS;
329	
330	  if (mod_t::coprime(r, N)) return SUCCESS;
331	
332	  if (!resample_until_coprime) {
333	    r = 0;
334	    return coinbase::error(E_CRYPTO, "paillier_t::rand_N_star: gcd(r, N) != 1");
335	  }
336	
337	  do {
338	    r = bn_t::rand(N);
339	  } while (!mod_t::coprime(r, N));
340	  return SUCCESS;
341	}
342	
343	error_t paillier_t::batch_verify_ciphers(const bn_t* ciphers, int n) const {
344	  if (n == 0) return SUCCESS;
345	  error_t rv = UNINITIALIZED_ERROR;
346	  for (int i = 0; i < n; i++) {
347	    if (rv = coinbase::crypto::check_open_range(0, ciphers[i], NN)) return rv;
348	  }
349	
350	  bn_t prod = ciphers[0];
351	  for (int i = 1; i < n; i++) {
352	    MODULO(N) prod *= ciphers[i];
353	  }
354	  if (!mod_t::coprime(prod, N)) return coinbase::error(E_CRYPTO);
355	
356	  return SUCCESS;
357	}
