128	static BIGNUM bn_buf(BN_ULONG* ptr, int size) {
129	  BIGNUM a;
130	  a.d = ptr;
131	  a.top = a.dmax = size;
132	  a.flags = BN_FLG_FIXED_TOP | BN_FLG_STATIC_DATA | BN_FLG_CONSTTIME;
133	  a.neg = 0;
134	  return a;
135	}
