137	static BIGNUM bn_skip(BIGNUM a, int n) {
138	  a.d += n;
139	  a.top -= n;
140	  a.dmax -= n;
141	  return a;
142	}
143	
144	static void bn_copy(BIGNUM r, BIGNUM a) {
145	  int len = std::min(a.top, r.top);
146	  std::copy(a.d, a.d + len, r.d);
147	  if (r.top > len) std::fill(r.d + len, r.d + r.top, 0);
148	}
