150	enum { BN_ULONG_BITS = sizeof(BN_ULONG) * 8 };
151	static constexpr int MAX_MODULUS_WORDS = (mod_t::MAX_MODULUS_BITS + BN_ULONG_BITS - 1) / BN_ULONG_BITS;
152	
153	void mod_t::_mul(bn_t& r, const bn_t& a, const bn_t& b) const {
154	  if (vartime_scope) {
155	    int res = BN_mod_mul(r, a, b, m, bn_t::thread_local_storage_bn_ctx());
156	    cb_assert(res);
157	    return;
158	  }
159	
160	  check(a);
161	  check(b);
162	
163	  const BIGNUM& aa = *(const BIGNUM*)a;
164	  const BIGNUM& bb = *(const BIGNUM*)b;
165	  if (aa.top == 0 || bb.top == 0) {
166	    r = 0;
167	    return;
168	  }
169	
170	  cb_assert(aa.top >= 0 && bb.top >= 0 && aa.top + bb.top <= 2 * MAX_MODULUS_WORDS);
171	  // Intentional bounded VLA: modulus size is capped by MAX_MODULUS_BITS.
172	  // Keep this on the stack to avoid heap allocation in the modular multiplication hot path.
173	  BN_ULONG buf[aa.top + bb.top];
174	  bn_mul_normal(buf, aa.d, aa.top, bb.d, bb.top);
175	
176	  BIGNUM temp = bn_buf(buf, aa.top + bb.top);
177	  _mod(*(BIGNUM*)r, temp);
178	}
