182	static BN_ULONG div_words_by_two(int n, BN_ULONG* r) {
183	  uint64_t carry = 0;
184	  for (int i = n - 1; i >= 0; i--) {
185	    uint64_t c = r[i] << (BN_ULONG_BITS - 1);
186	    r[i] = (r[i] >> 1) | carry;
187	    carry = c;
188	  }
189	  return carry;
190	}
