192	// Returns a mask of all bits set (0xFFFFFFFFF...) if flag == true,
193	// or 0 if flag == false, with a small inline assembly barrier to keep
194	// the compiler from optimizing it away under LTCG or at high -O levels.
195	static inline BN_ULONG constant_time_mask_ulong(bool flag) {
196	  BN_ULONG mask = (BN_ULONG)0 - (BN_ULONG)flag;
197	  mask = constant_time_value_barrier(mask);
198	  return mask;
199	}
200	
201	static void cnd_swap(int n, bool flag, BN_ULONG a[], BN_ULONG b[]) {
202	  BN_ULONG mask = constant_time_mask_ulong(flag);
203	  for (int i = 0; i < n; i++) {
204	    BN_ULONG delta = (a[i] ^ b[i]) & mask;
205	    a[i] ^= delta;
206	    b[i] ^= delta;
207	  }
208	}
