210	static BN_ULONG ct_bn_add_words(BN_ULONG* r, const BN_ULONG* a, const BN_ULONG* b, int n) {
211	  BN_ULONG carry = 0;
212	  for (int i = 0; i < n; i++) {
213	    r[i] = addx(a[i], b[i], (uint64_t&)carry);
214	  }
215	  return carry;
216	}
