218	static BN_ULONG ct_bn_sub_words(BN_ULONG* r, const BN_ULONG* a, const BN_ULONG* b, int n) {
219	  BN_ULONG borrow = 0;
220	  for (int i = 0; i < n; i++) {
221	    r[i] = subx(a[i], b[i], (uint64_t&)borrow);
222	  }
223	  return borrow;
224	}
225	
226	static BN_ULONG cnd_add_words(int n, BN_ULONG r[], bool flag, const BN_ULONG a[]) {
227	  cb_assert(n > 0 && n <= MAX_MODULUS_WORDS);
228	  BN_ULONG mask = constant_time_mask_ulong(flag);
229	  // Intentional bounded VLA: preserving the temp array keeps ct_bn_add_words()'s carry chain optimizable.
230	  BN_ULONG temp[n];
231	  for (int i = 0; i < n; i++) temp[i] = a[i] & mask;
232	  return ct_bn_add_words(r, r, temp, n);
233	}
234	
235	static BN_ULONG cnd_sub_words(int n, BN_ULONG r[], bool flag, const BN_ULONG a[]) {
236	  cb_assert(n > 0 && n <= MAX_MODULUS_WORDS);
237	  BN_ULONG mask = constant_time_mask_ulong(flag);
238	  // Intentional bounded VLA: preserving the temp array keeps ct_bn_sub_words()'s borrow chain optimizable.
239	  BN_ULONG temp[n];
240	  for (int i = 0; i < n; i++) temp[i] = a[i] & mask;
241	  return ct_bn_sub_words(r, r, temp, n);
242	}
243	
244	static BN_ULONG cnd_neg_words(int n, BN_ULONG r[], bool flag) {
245	  cb_assert(n > 0 && n <= MAX_MODULUS_WORDS);
246	  BN_ULONG mask = constant_time_mask_ulong(flag);
247	  for (int i = 0; i < n; i++) r[i] ^= mask;
248	  // Intentional bounded VLA: see cnd_add_words().
249	  BN_ULONG temp[n];
250	  std::fill(temp, temp + n, 0);
251	  temp[0] = (BN_ULONG)flag;
252	  return ct_bn_add_words(r, r, temp, n);
253	}
