256	void mod_t::scr_inv(bn_t& res, const bn_t& in) const {
257	  cb_assert(in < m);
258	  auto q = (const BIGNUM*)m;
259	  int n = q->top;
260	
261	  auto x = (const BIGNUM*)in;
262	  bn_t val;
263	
264	  auto r = (BIGNUM*)res;
265	  auto exp_res = bn_wexpand(r, n);
266	  cb_assert(exp_res);
267	  r->top = n;
268	
269	  const BN_ULONG* m = q->d;
270	  cb_assert(n > 0 && n <= MAX_MODULUS_WORDS);
271	  // Intentional bounded VLAs: n is capped by MAX_MODULUS_BITS. These buffers are hot scratch state for SCR inversion.
272	  BN_ULONG a[n];
273	  auto top = std::min(x->top, n);
274	  std::copy(x->d, x->d + top, a);
275	  std::fill(a + top, a + n, 0);  // a
276	  BN_ULONG b[n];
277	  std::copy(m, m + n, b);  // b = m
278	  BN_ULONG u[n];
279	  std::fill(u, u + n, 0);
280	  u[0] = 1;  // u = 1
281	  BN_ULONG* v = r->d;
282	  std::fill(v, v + n, 0);  // v = 0
283	  // (m+1)/2, assuming m is odd, computed as (m >> 1) + 1 to avoid overflow when m = 2^k − 1
284	  BN_ULONG mp1o2[n];
285	  std::copy(m, m + n, mp1o2);
286	  div_words_by_two(n, mp1o2);
287	  ct_bn_add_words(mp1o2, mp1o2, u /*u == 1*/, n);
288	
289	  for (int i = 0; i < n * BN_ULONG_BITS * 2; i++) {
290	    bool a_is_odd = bool(a[0] & 1);
291	    bool underflow = bool(cnd_sub_words(n, a, a_is_odd, b));  // if (a_is_odd)   a -= b
292	    cnd_add_words(n, b, underflow, a);                        // if (underflow)  b += a
293	    cnd_neg_words(n, a, underflow);                           // if (underflow)  a = -a
294	    cnd_swap(n, underflow, u, v);                             // if (underflow)  swap u <=> v
295	    div_words_by_two(n, a);                                   // a /= 2
296	    bool borrow = bool(cnd_sub_words(n, u, a_is_odd, v));     // if (a_is_odd)   u -= v
297	    cnd_add_words(n, u, borrow, m);                           // if (borrow)     u += m;
298	    bool u_is_odd = bool(u[0] & 1);
299	    div_words_by_two(n, u);                // u /= 2
300	    cnd_add_words(n, u, u_is_odd, mp1o2);  // if (u_is_odd)   u += (m+1) / 2
301	  }
302	}
