304	void mod_t::random_masking_inv(bn_t& r, const bn_t& a) const {
305	  // Eventhough, this function is not truely constant-time, the running time is not dependent on the input (bn_t a).
306	  // Therefore, it doesn't leak any information of the input.
307	  // `BN_mod_inverse` fails when the operand is not invertible modulo `m`.
308	  // Even when `a` is invertible, a random mask might not be (e.g. if `m` is composite),
309	  // which would make `a*mask` non-invertible. Retry with a fresh mask.
310	  //
311	  // Bound retries to avoid hanging forever when `a` itself isn't invertible.
312	  constexpr int max_attempts = 128;
313	  bn_t mask;
314	  bn_t masked_a;
315	  for (int attempt = 0; attempt < max_attempts; attempt++) {
316	    mask = rand();
317	    if (mask == 0) continue;
318	
319	    masked_a = mul(a, mask);
320	    masked_a.correct_top();
321	    if (BN_mod_inverse(r, masked_a, m, bn_t::thread_local_storage_bn_ctx())) {
322	      r = mul(r, mask);
323	      return;
324	    }
325	  }
326	
327	  cb_assert(false && "mod_t::random_masking_inv failed");
328	}
