330	void mod_t::_inv(bn_t& r, const bn_t& a, inv_algo_e alg) const {
331	  if (vartime_scope) {
332	    a.correct_top();
333	    auto res = BN_mod_inverse(r, a, m, bn_t::thread_local_storage_bn_ctx());
334	    cb_assert(res && "vartime mod_t::inv failed");
335	  } else {
336	    if (alg == inv_algo_e::SCR) {
337	      scr_inv(r, a);
338	      return;
339	    } else if (alg == inv_algo_e::RandomMasking) {
340	      random_masking_inv(r, a);
341	      return;
342	    } else {
343	      cb_assert(false && "invalid algorithm");
344	    }
345	  }
346	}
