388	void mod_t::init(const bn_t& m) {
389	  cb_assert(m.get_bits_count() <= MAX_MODULUS_BITS && "modulus too large");
390	
391	  if (!mont) mont = BN_MONT_CTX_new();
392	  if (!mont) throw std::bad_alloc();
393	
394	  int res = BN_MONT_CTX_set(mont, m, bn_t::thread_local_storage_bn_ctx());
395	  cb_assert(res && "BN_MONT_CTX_set failed");
396	  this->m = m;
397	
398	  // barrett
399	  int k = (m.get_bits_count() + 63) / 64;
400	  bn_t b_pow_2k = bn_t(1).mul_2_pow(2 * k * 64);    // b^{2k}
401	  mu = b_pow_2k / m;                                // µ = ⌊b^{2k} / m⌋
402	  b_pow_k_plus1 = bn_t(1).mul_2_pow((k + 1) * 64);  // b^{k+1}
403	}
404	
405	static void barrett_partial_mul(int ResultLength, BN_ULONG r[], int M, const BN_ULONG u[], int N, const BN_ULONG v[]) {
406	  using TT = unsigned __int128;
407	  std::fill(r, r + ResultLength, 0);
408	
409	  for (int j = 0; j < N; ++j) {
410	    uint64_t k = 0;
411	    const auto m = std::min(M, ResultLength - j);
412	    for (auto i = 0; i < m; ++i) {
413	      TT t = TT(u[i]) * TT(v[j]) + r[i + j] + k;
414	      r[i + j] = uint64_t(t);
415	      k = t >> 64;
416	    }
417	    if (j + M < ResultLength) r[j + M] = k;
418	  }
419	}
