421	void mod_t::_mod(bn_t& r, const bn_t& x) const {
422	  const BIGNUM* _m = (const BIGNUM*)m;
423	  const BIGNUM* _x = (const BIGNUM*)x;
424	
425	  bn_t temp;
426	  if (_x->top > 2 * _m->top) {
427	    bn_t mSquare;
428	    BN_mul(mSquare, m, m, bn_t::thread_local_storage_bn_ctx());
429	
430	    mod_t mBig;
431	    mBig.init(mSquare);
432	    mBig._mod(temp, x);
433	    _x = (const BIGNUM*)temp;
434	  }
435	
436	  _mod(*(BIGNUM*)r, *_x);
437	}
438	
439	void mod_t::_mod(BIGNUM& r, const BIGNUM& x) const {
440	  if (vartime_scope) {
441	    int res = BN_div(nullptr, &r, &x, m, bn_t::thread_local_storage_bn_ctx());
442	    cb_assert(res);
443	    return;
444	  }
445	
446	  cb_assert(!x.neg);
447	
448	  const BIGNUM& mu = *(const BIGNUM*)this->mu;
449	  const BIGNUM& mm = *(const BIGNUM*)m;
450	  cb_assert(mu.top == mm.top + 1);
451	  cb_assert(x.top <= 2 * mm.top);
452	
453	  const int k = mm.top;
454	  if (x.top < k) {
455	    BN_copy(&r, &x);
456	    return;
457	  }
458	
459	  BIGNUM q1 = bn_skip(x, k - 1);  // q1 = x / b^(k-1)
460	
461	  int q2_len = q1.top + mu.top;
462	  cb_assert(k <= MAX_MODULUS_WORDS);
463	  cb_assert(q2_len <= 2 * MAX_MODULUS_WORDS + 2);
464	  // Intentional bounded VLA: q2_len is derived from operands capped by MAX_MODULUS_BITS.
465	  BN_ULONG q2_buf[q2_len];
466	  BIGNUM q2 = bn_buf(q2_buf, q2_len);
467	  bn_mul_normal(q2.d, q1.d, q1.top, mu.d, mu.top);  // q2 = q1 * mu;
468	
469	  BIGNUM q3 = bn_skip(q2, k + 1);  // q3 = q2 / b^(k+1)
470	
471	  // Intentional bounded VLA: k <= MAX_MODULUS_WORDS.
472	  BN_ULONG r2_buf[k + 1];
473	  BIGNUM r2 = bn_buf(r2_buf, k + 1);
474	  barrett_partial_mul(r2.top, r2.d, q3.top, q3.d, mm.top, mm.d);  // r2 = partial_mul<k + 1>(q3, modulus);
475	
476	  BIGNUM r1 = bn_buf(q2_buf, k + 1);
477	  bn_copy(r1, x);  // r1 = x mod b^(k+1)
478	
479	  uint64_t borrow = ct_bn_sub_words(r1.d, r1.d, r2.d, k + 1);
480	
481	  r2 = bn_buf(r2_buf, k);
482	  borrow = ct_bn_sub_words(r2.d, r1.d, mm.d, k);
483	  borrow &= (r1.d[k] == 0);
484	  uint64_t mask = constant_time_mask_64(borrow);
485	  for (int i = 0; i < k; i++) {
486	    r1.d[i] = masked_select(mask, r1.d[i], r2.d[i]);
487	  }
488	
489	  borrow = ct_bn_sub_words(r2.d, r1.d, mm.d, k);
490	  mask = (uint64_t)0 - borrow;
491	  for (int i = 0; i < k; i++) {
492	    r1.d[i] = masked_select(mask, r1.d[i], r2.d[i]);
493	  }
494	
495	  auto exp_res = bn_wexpand(&r, k);
496	  cb_assert(exp_res);
497	  r.flags |= BN_FLG_CONSTTIME;
498	  r.top = k;
499	
500	  bn_copy(r, r1);
501	}
