516	bool mod_t::coprime(const bn_t& a, const mod_t& m) {
517	  if (vartime_scope) {
518	    return bn_t::gcd(a, m.m) == 1;
519	  }
520	  bn_t a_mod = m.mod(a);
521	  try {
522	    bn_t a_inv = m.inv(a_mod);  // may cb_assert if not invertible
523	    return m.mul(a_inv, a_mod) == 1;
524	  } catch (const coinbase::assertion_failed_t&) {
525	    // Inversion failed => not coprime
526	    return false;
527	  }
528	}
