530	// static
531	bn_t mod_t::N_inv_mod_phiN_2048(const bn_t& N, const bn_t& phiN) {
532	  if (vartime_scope) {
533	    bn_t result;
534	    auto res = BN_mod_inverse(result, N, phiN, bn_t::thread_local_storage_bn_ctx());
535	    cb_assert(res);
536	    return result;
537	  }
538	  cb_assert(!phiN.is_odd());
539	  cb_assert(N.is_odd());
540	  bn_t N_minus_phiN = LARGEST_PRIME_MOD_2048.sub(N, phiN);
541	  N_minus_phiN.correct_top();
542	  mod_t mod_N_minus_phiN(N_minus_phiN, false);
543	  bn_t alpha = mod_N_minus_phiN.inv(mod_N_minus_phiN.mod(phiN));  // alpha = m^-1 % a
544	  bn_t beta = mod_t(N).inv(N_minus_phiN);                         // beta = a^-1 % (m+a)
545	  bn_t result;
546	  MODULO(LARGEST_PRIME_MOD_2048) { result = beta + alpha - N_minus_phiN; }
547	  return result;
548	}
