23	
24	bool booth_wnaf_t::get(unsigned& value, bool& neg) {
25	  if (back) {
26	    if (index < 0) return false;
27	  } else {
28	    if (index >= bits) return false;
29	  }
30	
31	  unsigned val;
32	  if (index == 0) {
33	    val = unsigned(data[0]) << 1;
34	  } else {
35	    int off = (index - 1) / 8;
36	    val = unsigned(data[off]);
37	    if (off + 1 < sizeof(data)) val |= unsigned(data[off + 1]) << 8;
38	    val = val >> ((index - 1) % 8);
39	  }
40	
41	  const unsigned kMask = (1 << (win + 1)) - 1;
42	  val = val & kMask;
43	
44	  unsigned s, d;
45	  s = ~((val >> win) - 1);
46	  d = (1 << (win + 1)) - val - 1;
47	  d = (d & s) | (val & ~s);
48	  d = (d >> 1) + (d & 1);
49	  neg = bool(s & 1);
50	  value = d;
51	
52	  if (back)
53	    index -= win;
54	  else
55	    index += win;
56	  return true;
57	}
