60	void ct_get3(__m128i* dst, const __m128i* precomp, int line_size, unsigned index) {
61	  __m128i lo1, hi1, lo2, hi2, lo3, hi3;
62	  lo1 = hi1 = lo2 = hi2 = lo3 = hi3 = _mm_setzero_si128();
63	  for (unsigned i = 0; i < line_size; i++) {
64	    __m128i mask = _mm_set1_epi32(-(index == i));
65	    lo1 = _mm_or_si128(lo1, _mm_and_si128(mask, _mm_load_si128(precomp + 0)));
66	    hi1 = _mm_or_si128(hi1, _mm_and_si128(mask, _mm_load_si128(precomp + 1)));
67	    lo2 = _mm_or_si128(lo2, _mm_and_si128(mask, _mm_load_si128(precomp + 2)));
68	    hi2 = _mm_or_si128(hi2, _mm_and_si128(mask, _mm_load_si128(precomp + 3)));
69	    lo3 = _mm_or_si128(lo3, _mm_and_si128(mask, _mm_load_si128(precomp + 4)));
70	    hi3 = _mm_or_si128(hi3, _mm_and_si128(mask, _mm_load_si128(precomp + 5)));
71	    precomp += 2 * 3;
72	  }
73	  _mm_storeu_si128(dst + 0, lo1);
74	  _mm_storeu_si128(dst + 1, hi1);
75	  _mm_storeu_si128(dst + 2, lo2);
76	  _mm_storeu_si128(dst + 3, hi2);
77	  _mm_storeu_si128(dst + 4, lo3);
78	  _mm_storeu_si128(dst + 5, hi3);
79	}
