79	  bn_t x1, y1, x2, y2;
80	  EC_POINT_get_affine_coordinates(g1, p1, x1, y1, NULL);
81	  EC_POINT_get_affine_coordinates(g2, p2, x2, y2, NULL);
82	  return x1 == x2 && y1 == y2;
83	}
