85	static const char* crypto_ec_group_2_name(const EC_GROUP* group) {
86	  int id = EC_GROUP_get_curve_name(group);
87	  switch (id) {
88	    case NID_X9_62_prime256v1:
89	      return SN_X9_62_prime256v1;
90	    case NID_secp256k1:
91	      return SN_secp256k1;
92	  }
93	  return nullptr;
94	}
