96	error_t ossl_ecdsa_verify(const EC_GROUP* group, EC_POINT* point, mem_t hash, mem_t signature) {
97	  uint8_t oct[65];
98	  cb_assert(EC_POINT_point2oct(group, point, POINT_CONVERSION_UNCOMPRESSED, oct, 65,
99	                               bn_t::thread_local_storage_bn_ctx()) > 0);
100	
101	  OSSL_PARAM_BLD* param_bld = OSSL_PARAM_BLD_new();
102	  cb_assert(param_bld);
103	  cb_assert(OSSL_PARAM_BLD_push_utf8_string(param_bld, "group", crypto_ec_group_2_name(group), 0) > 0);
104	  cb_assert(OSSL_PARAM_BLD_push_octet_string(param_bld, "pub", oct, 65) > 0);
105	  OSSL_PARAM* params = OSSL_PARAM_BLD_to_param(param_bld);
106	  cb_assert(params);
107	  EVP_PKEY_CTX* ctx = EVP_PKEY_CTX_new_from_name(NULL, "EC", NULL);
108	  cb_assert(ctx);
109	  cb_assert(EVP_PKEY_fromdata_init(ctx) > 0);
110	  EVP_PKEY* pkey = NULL;
111	  cb_assert(EVP_PKEY_fromdata(ctx, &pkey, EVP_PKEY_PUBLIC_KEY, params) > 0);
112	  EVP_PKEY_CTX_free(ctx);
113	  OSSL_PARAM_BLD_free(param_bld);
114	  OSSL_PARAM_free(params);
115	
116	  ctx = EVP_PKEY_CTX_new(pkey, NULL);
117	  cb_assert(ctx);
118	  cb_assert(EVP_PKEY_verify_init(ctx) > 0);
119	  int res = EVP_PKEY_verify(ctx, signature.data, signature.size, hash.data, hash.size);
120	  EVP_PKEY_CTX_free(ctx);
121	
122	  EVP_PKEY_free(pkey);
123	  if (res != 1) return coinbase::error(E_CRYPTO, "EVP_PKEY_verify failed in ossl_ecdsa_verify");
124	  return SUCCESS;
125	}
126	
127	buf_t ossl_ecdsa_sign(const EC_GROUP* group, BIGNUM* x, mem_t hash) {
128	  OSSL_PARAM_BLD* param_bld = OSSL_PARAM_BLD_new();
129	  cb_assert(param_bld);
130	  cb_assert(OSSL_PARAM_BLD_push_utf8_string(param_bld, "group", crypto_ec_group_2_name(group), 0) > 0);
131	  cb_assert(OSSL_PARAM_BLD_push_BN(param_bld, "priv", x) > 0);
132	  OSSL_PARAM* params = OSSL_PARAM_BLD_to_param(param_bld);
133	  cb_assert(params);
134	  EVP_PKEY_CTX* ctx = EVP_PKEY_CTX_new_from_name(NULL, "EC", NULL);
135	  cb_assert(ctx);
136	  cb_assert(EVP_PKEY_fromdata_init(ctx) > 0);
137	  EVP_PKEY* pkey = NULL;
138	  cb_assert(EVP_PKEY_fromdata(ctx, &pkey, EVP_PKEY_KEYPAIR, params) > 0);
139	  EVP_PKEY_CTX_free(ctx);
140	  OSSL_PARAM_BLD_free(param_bld);
141	  OSSL_PARAM_free(params);
142	
143	  ctx = EVP_PKEY_CTX_new(pkey, NULL);
144	  cb_assert(ctx);
145	  cb_assert(EVP_PKEY_sign_init(ctx) > 0);
146	  size_t siglen = 0;
147	  cb_assert(EVP_PKEY_sign(ctx, nullptr, &siglen, hash.data, hash.size) > 0);
148	  buf_t der((int)siglen);
149	  cb_assert(EVP_PKEY_sign(ctx, der.data(), &siglen, hash.data, hash.size) > 0);
150	  EVP_PKEY_CTX_free(ctx);
151	
152	  EVP_PKEY_free(pkey);
153	  return der;
154	}
