309	error_t ecurve_ossl_t::from_bin(ecc_point_t& P, mem_t bin) const {
310	  if (bin.size > 0 && bin[0] == 0)  // infinity
311	  {
312	    if (bin.size != 1 + size() && bin.size != 1 + size() * 2) return coinbase::error(E_FORMAT);
313	    for (int i = 0; i < bin.size; i++)
314	      if (bin[i]) return coinbase::error(E_CRYPTO);
315	    bin.size = 1;
316	  }
317	
318	  if (0 >= EC_POINT_oct2point(group, P, bin.data, bin.size, bn_t::thread_local_storage_bn_ctx())) {
319	    return openssl_error("EC_POINT_oct2point error, data-size=" + strext::itoa(bin.size));
320	  }
321	  return SUCCESS;
322	}
