367	error_t ecc_pub_key_t::verify_schnorr(mem_t message, mem_t signature) const {
368	  if (signature.size != curve.size() * 2) return coinbase::error(E_FORMAT);
369	
370	  const auto& G = curve.generator();
371	  const mod_t& q = curve.order();
372	  ecc_point_t Q = *this;
373	
374	  bn_t e = bn_t::from_bin(signature.take(curve.size()));
375	  bn_t s = bn_t::from_bin(signature.skip(curve.size()));
376	
377	  if (e <= 0 || e >= q) return coinbase::error(E_CRYPTO);
378	  if (s <= 0 || s >= q) return coinbase::error(E_CRYPTO);
379	
380	  ecc_point_t R = s * G + e * Q;  // s * G + e * Q = (k - e * x) * G + e * x * G = (k - e * x + e * x) * G = k * G = R
381	
382	  bn_t e_tag = bn_t(crypto::sha256_t::hash(Q, R, message)) % q;
383	  if (e_tag != e) return coinbase::error(E_CRYPTO);
384	  return SUCCESS;
385	}
