438	error_t sig_with_pub_key_t::verify(mem_t hash) const {
439	  error_t rv = UNINITIALIZED_ERROR;
440	  const auto& curve = Q.get_curve();
441	  if (rv = curve.check(Q)) return coinbase::error(rv, "sig_with_pub_key_t::verify: invalid public key");
442	  crypto::ecc_pub_key_t ecc(Q);
443	  if (rv = ecc.verify(hash, sig)) return coinbase::error(E_CRYPTO, "sig_with_pub_key_t::verify: invalid signature");
444	  return SUCCESS;
445	}
446	
447	error_t sig_with_pub_key_t::verify_all(const ecc_point_t& Q, mem_t hash,
448	                                       const std::vector<sig_with_pub_key_t>& sigs)  // static
449	{
450	  error_t rv = UNINITIALIZED_ERROR;
451	  if (sigs.empty()) return coinbase::error(E_BADARG, "sig_with_pub_key_t::verify_all: no signatures provided");
452	
453	  const auto curve = sigs[0].Q.get_curve();
454	  if (!curve || Q.get_curve() != curve)
455	    return coinbase::error(E_BADARG, "sig_with_pub_key_t::verify_all: mixed curves");
456	
457	  ecc_point_t QSum = curve.infinity();
458	
459	  for (const auto& s : sigs) {
460	    if (s.Q.get_curve() != curve) return coinbase::error(E_BADARG, "sig_with_pub_key_t::verify_all: mixed curves");
461	    if (rv = s.verify(hash)) return rv;
462	    QSum += s.Q;
463	  }
464	  if (Q != QSum) return coinbase::error(E_CRYPTO, "sig_with_pub_key_t::verify_all: Schnorr public key mismatch");
465	  return SUCCESS;
466	}
