479	buf_t ecc_prv_key_t::sign_schnorr(mem_t message) const {
480	  const auto& G = curve.generator();
481	  const mod_t& q = curve.order();
482	
483	  bn_t x = value();
484	  ecc_point_t Q = x * G;
485	  bn_t k = bn_t::rand(q);
486	  ecc_point_t R = k * G;
487	  bn_t e = bn_t(crypto::sha256_t::hash(Q, R, message)) % q;
488	  bn_t s;
489	  MODULO(q) s = k - e * x;
490	
491	  return e.to_bin(curve.size()) + s.to_bin(curve.size());
492	}
