496	ecurve_t ecurve_t::find(int openssl_id) {
497	  if (openssl_id == 0) return nullptr;
498	
499	  for (int i = 0; i < sizeof(g_curves) / sizeof(g_curves[0]); i++) {
500	    ecurve_t curve = ecurve_t(g_curves[i]);
501	    if (curve.type() == ecurve_type_e::ossl && !curve.get_group()) continue;
502	    if (openssl_id == curve.get_openssl_code()) return curve;
503	  }
504	  crypto::error("Curve not found, openssl-code=" + strext::itoa(openssl_id));
505	  return nullptr;
506	}
507	
508	ecurve_t ecurve_t::find(const EC_GROUP* group) {
509	  int name_id = EC_GROUP_get_curve_name(group);
510	  if (name_id) return find(name_id);
511	
512	  for (int i = 0; i < sizeof(g_curves) / sizeof(g_curves[0]); i++) {
513	    ecurve_t curve = ecurve_t(g_curves[i]);
514	    const EC_GROUP* curve_group = curve.get_group();
515	    if (!curve_group) continue;
516	
517	    if (ossl_equ_groups(group, curve_group)) return curve;
518	  }
519	  crypto::error("Curve not found by GROUP");
520	  return nullptr;
521	}
