737	void ecc_point_t::convert_fixed_curve(coinbase::converter_t& converter, ecurve_t curve) {
738	  int n = curve.compressed_point_bin_size();
739	
740	  if (converter.is_write()) {
741	    if (!converter.is_calc_size()) {
742	      cb_assert(get_curve() == curve);
743	      to_compressed_bin(converter.current());
744	    }
745	  } else {
746	    error_t rv = UNINITIALIZED_ERROR;
747	    if (converter.is_error() || !converter.at_least(n)) {
748	      converter.set_error();
749	      return;
750	    }
751	    if (rv = from_bin(curve, mem_t(converter.current(), n))) {
752	      converter.set_error(rv);
753	      return;
754	    }
755	    if (rv = curve.check(*this)) {
756	      converter.set_error(rv);
757	      return;
758	    }
759	  }
760	
761	  converter.forward(n);
762	}
