846	ecc_point_t ecc_point_t::weighted_sum(const bn_t& x0, const ecc_point_t& P0, const bn_t& x1, const ecc_point_t& P1) {
847	  if (is_vartime_scope()) {
848	    return x0 * P0 + x1 * P1;
849	  } else {
850	    auto curve = P0.get_curve();
851	    switch (curve.ptr->ct_add_support()) {
852	      case ct_add_support_e::Full: {
853	        crypto::consttime_point_add_scope_t consttime_point_add_scope;
854	        return x0 * P0 + x1 * P1;
855	      }
856	      case ct_add_support_e::None:
857	      default: {
858	        bn_t bias = bn_t::rand(curve.order());
859	        return curve.mul_add(bias, P0, x0) + curve.mul_add(-bias, P1, x1);
860	      }
861	    }
862	  }
863	}
