934	error_t ecdsa_signature_t::from_der(ecurve_t curve, mem_t in) {
935	  const_byte_ptr in_ptr = in.data;
936	  ECDSA_SIG* sig_ptr = d2i_ECDSA_SIG(NULL, &in_ptr, in.size);
937	  if (!sig_ptr) return coinbase::error(E_FORMAT);
938	
939	  const BIGNUM* r_ptr = nullptr;
940	  const BIGNUM* s_ptr = nullptr;
941	
942	  ECDSA_SIG_get0(sig_ptr, &r_ptr, &s_ptr);
943	  r = bn_t(r_ptr);
944	  s = bn_t(s_ptr);
945	  ECDSA_SIG_free(sig_ptr);
946	
947	  this->curve = curve;
948	  return SUCCESS;
949	}
