951	int ecdsa_signature_t::to_der(byte_ptr out) const {
952	  ECDSA_SIG* sig_ptr = make_ecdsa_sig(r, s);
953	
954	  int out_size = i2d_ECDSA_SIG(sig_ptr, NULL);
955	  if (out && out_size > 0) i2d_ECDSA_SIG(sig_ptr, &out);
956	
957	  ECDSA_SIG_free(sig_ptr);
958	
959	  if (out_size <= 0) return -1;
960	  return out_size;
961	}
