977	error_t ecdsa_signature_t::get_recovery_code(mem_t in, const ecc_point_t& pub_key, int& recovery_code) {
978	  error_t rv = UNINITIALIZED_ERROR;
979	  int curve_size = curve.size();
980	  if (in.size >= curve_size) in.size = curve.size();
981	  bn_t e = bn_t::from_bin(in);
982	
983	  buf_t oct(1 + curve_size);
984	  oct[0] = 2;
985	  r.to_bin(oct.data() + 1, curve_size);
986	  ecc_point_t R;
987	  if (rv = R.from_oct(curve, oct)) return rv;
988	  if (rv = curve.check(R)) return coinbase::error(rv, "ecdsa_signature_t::get_recovery_code: invalid R");
989	
990	  const mod_t& q = curve.order();
991	  const auto& G = curve.generator();
992	
993	  bn_t r_inv = q.inv(r);
994	
995	  ecc_point_t Q = r_inv * (s * R - e * G);
996	  if (Q == pub_key) {
997	    recovery_code = 0;
998	    return SUCCESS;
999	  }
1000	
1001	  R.invert();
1002	  Q = r_inv * (s * R - e * G);
1003	  if (Q == pub_key) {
1004	    recovery_code = 1;
1005	    return SUCCESS;
1006	  }
1007	
1008	  return coinbase::error(E_CRYPTO);
1009	}
1010	
1011	error_t ecdsa_signature_t::recover_pub_key(mem_t in, int recovery_code, ecc_point_t& pub_key) {
1012	  error_t rv = UNINITIALIZED_ERROR;
1013	  if (recovery_code != 0 && recovery_code != 1) return coinbase::error(E_CRYPTO);
1014	
1015	  int curve_size = curve.size();
1016	  if (in.size >= curve_size) in.size = curve.size();
1017	  bn_t e = bn_t::from_bin(in);
1018	
1019	  buf_t oct(1 + curve_size);
1020	  oct[0] = 2 + recovery_code;
1021	  r.to_bin(oct.data() + 1, curve_size);
1022	  ecc_point_t R;
1023	  if (rv = R.from_oct(curve, oct)) return rv;
1024	  if (rv = curve.check(R)) return coinbase::error(rv, "ecdsa_signature_t::recover_pub_key: invalid R");
1025	
1026	  const mod_t& q = curve.order();
1027	  const auto& G = curve.generator();
1028	  bn_t r_inv = q.inv(r);
1029	  pub_key = r_inv * (s * R - e * G);
1030	  return SUCCESS;
1031	}
