44	// Constant-time addition for secp256k1_gej points for all inputs (including infinity).
45	// Implementation strategy:
46	// - Use libsecp256k1's `secp256k1_gej_add_ge` (side-channel resistant, handles degeneracy),
47	//   which requires the second operand in affine form and non-infinity.
48	// - If the second operand is infinity, cmov it to generator (any fixed non-infinity point),
49	//   perform the addition, then cmov the result back to `a`.
50	static void secp256k1_gej_add_consttime_full(secp256k1_gej* r, const secp256k1_gej* a, const secp256k1_gej* b) {
51	  SECP256K1_GEJ_VERIFY(a);
52	  SECP256K1_GEJ_VERIFY(b);
53	
54	  const int b_is_inf = b->infinity;
55	
56	  secp256k1_gej b_noninf = *b;
57	  secp256k1_gej_cmov(&b_noninf, &G, b_is_inf);  // ensure non-infinity for affine conversion
58	
59	  // Convert a copy of b_noninf to affine (constant-time inversion via secp256k1_fe_inv).
60	  secp256k1_ge b_ge;
61	  secp256k1_gej b_tmp = b_noninf;
62	  secp256k1_ge_set_gej(&b_ge, &b_tmp);
63	  VERIFY_CHECK(!b_ge.infinity);
64	
65	  // Add in (side-channel resistant) constant-time.
66	  secp256k1_gej_add_ge(r, a, &b_ge);
67	
68	  // If original `b` was infinity, the result should be `a`.
69	  secp256k1_gej_cmov(r, a, b_is_inf);
70	
71	  SECP256K1_GEJ_VERIFY(r);
72	}
