188	void ecurve_secp256k1_t::mul_add(const bn_t& n, const ecc_point_t& P, const bn_t& m, ecc_point_t& R) const {
189	  bn_t nn;
190	  MODULO(q) nn = n + 0;
191	  bn_t mm;
192	  MODULO(q) mm = m + 0;
193	
194	  buf_t bin_n = nn.to_bin(32);
195	  buf_t bin_m = mm.to_bin(32);
196	  secp256k1_scalar scalar_n;
197	  secp256k1_scalar scalar_m;
198	  secp256k1_scalar_set_b32(&scalar_n, bin_n.data(), nullptr);
199	  secp256k1_scalar_set_b32(&scalar_m, bin_m.data(), nullptr);
200	
201	  if (is_vartime_scope()) {
202	    // Verifier code paths allow variable-time operations and require robustness for all inputs.
203	    secp256k1_ecmult((secp256k1_gej*)R.secp256k1, (const secp256k1_gej*)P.secp256k1, &scalar_m, &scalar_n);
204	    secp256k1_scalar_clear(&scalar_m);
205	    secp256k1_scalar_clear(&scalar_n);
206	    return;
207	  }
208	
209	  secp256k1_gej Rn;
210	  secp256k1_ecmult_gen(&secp256k1_ecmult_gen_ctx, &Rn, &scalar_n);
211	
212	  // Convert P to affine coordinates for secp256k1_ecmult_const.
213	  // Use the constant-time conversion (secp256k1_fe_inv via secp256k1_ge_set_gej).
214	  // Also ensure we never feed infinity into secp256k1_ge_set_gej by cmov'ing to generator.
215	  secp256k1_gej Pj = *(const secp256k1_gej*)P.secp256k1;
216	  const int P_is_inf = Pj.infinity;
217	  secp256k1_gej_cmov(&Pj, &G, P_is_inf);
218	
219	  secp256k1_ge P_ge;
220	  secp256k1_ge_set_gej(&P_ge, &Pj);
221	  VERIFY_CHECK(!P_ge.infinity);
222	
223	  // Compute Rm = mP in constant-time
224	  secp256k1_gej Rm;
225	  secp256k1_ecmult_const(&Rm, &P_ge, &scalar_m);
226	
227	  // If original P was infinity, mP is infinity.
228	  secp256k1_gej inf;
229	  secp256k1_gej_set_infinity(&inf);
230	  secp256k1_gej_cmov(&Rm, &inf, P_is_inf);
231	
232	  secp256k1_gej R_sum;
233	  secp256k1_gej_add_consttime_full(&R_sum, &Rm, &Rn);
234	  memcpy(R.secp256k1, &R_sum, sizeof(R_sum));
235	
236	  secp256k1_scalar_clear(&scalar_m);
237	  secp256k1_scalar_clear(&scalar_n);
238	}
