291	void ecurve_secp256k1_t::get_coordinates(const std::vector<ecc_point_t>& P, std::vector<bn256_t>& x,
292	                                         std::vector<bn256_t>& y) {
293	  int n = int(P.size());
294	  if (n == 0) {
295	    x.clear();
296	    y.clear();
297	    return;
298	  }
299	
300	  std::vector<secp256k1_gej> gej(n);
301	  std::vector<secp256k1_ge> ge(n);
302	  for (int i = 0; i < n; i++) {
303	    cb_assert(P[i].valid());
304	    cb_assert(P[i].get_curve() == curve_secp256k1);
305	    gej[i] = *(const secp256k1_gej*)P[i].secp256k1;
306	  }
307	  secp256k1_ge_set_all_gej_var(ge.data(), gej.data(), n);
308	  x.resize(n);
309	  y.resize(n);
310	  for (int i = 0; i < n; i++) {
311	    uint8_t bin[32];
312	    secp256k1_fe_normalize_var(&ge[i].x);
313	    secp256k1_fe_get_b32(bin, &ge[i].x);
314	    x[i] = bn256_t::from_bin(mem_t(bin, 32));
315	    secp256k1_fe_normalize_var(&ge[i].y);
316	    secp256k1_fe_get_b32(bin, &ge[i].y);
317	    y[i] = bn256_t::from_bin(mem_t(bin, 32));
318	  }
319	}
