390	error_t verify(const ecc_point_t& pub_key, mem_t m, mem_t sig) {
391	  error_t rv = UNINITIALIZED_ERROR;
392	  if (sig.size != 64) return coinbase::error(E_BADARG, "BIP340 verify: sig size != 64");
393	  if (m.size != 32) return coinbase::error(E_BADARG, "BIP340 verify: msg size != 32");
394	  if (!m.data) return coinbase::error(E_BADARG, "BIP340 verify: msg is null");
395	
396	  ecurve_t curve = curve_secp256k1;
397	  const mod_t& q = curve.order();
398	  const ecc_generator_point_t& G = curve.generator();
399	  if (pub_key.get_curve() != curve) return coinbase::error(E_BADARG, "BIP340 verify: only secp256k1 supported");
400	
401	  bn_t r = bn_t::from_bin(sig.take(32));
402	  if (r >= curve.p()) return coinbase::error(E_CRYPTO, "BIP340 verify: sig r not in the field");
403	
404	  bn_t s = bn_t::from_bin(sig.skip(32));
405	  if (s >= q) return coinbase::error(E_CRYPTO, "BIP340 verify: sig s not in [0, q)");
406	
407	  buf_t oct = pub_key.to_compressed_bin();
408	  oct[0] = 2;  // even only
409	  ecc_point_t Q;
410	  if (rv = Q.from_bin(curve, oct)) return rv;
411	
412	  bn_t e = hash_message(r, Q, m);
413	  ecc_point_t R = s * G - e * Q;
414	  if (R.is_infinity()) return coinbase::error(E_CRYPTO, "BIP340 verify: R is infinity");
415	  if (R.get_y().is_odd()) return coinbase::error(E_CRYPTO, "BIP340 verify: R.y is odd");
416	  if (r != R.get_x()) return coinbase::error(E_CRYPTO, "BIP340 verify: r != R.x");
417	
418	  return SUCCESS;
419	}
